+		},
+		{
+			name:     "whitespace only lines preserved",
+			input:    "line1\n   \nline3",
+			expected: []string{"line1", "   ", "line3"},
+		},
+		{
+			name:     "single newline only",
+			input:    "\n",
+			expected: []string{""}, // split produces ["", ""], trailing empty removed = [""]
+		},
+		{
+			name:     "multiple consecutive newlines",
+			input:    "\n\n\n",
+			expected: []string{"", "", ""}, // split produces ["", "", "", ""], trailing empty removed = ["", "", ""]
